# --- F7: doctor (env-health diagnoser) --------------------------------------

# Each check returns rows of (name, status, detail). Statuses:
#   PASS - the resource exists and is usable.
#   FAIL - missing/broken; exit code 1 if any present.
#   WARN - degraded but does not block build/test.
#   INFO - informational (host facts), never affects exit code.
_DoctorRow = tuple[str, str, str]


def _read_hybrid_toolchain() -> str | None:
    """Locate HYBRID_TOOLCHAIN: env first, then config.env fallback."""
    tc = os.environ.get("HYBRID_TOOLCHAIN")
    if tc:
        return tc
    cfg = REPO_ROOT / "config.env"
    if not cfg.is_file():
        return None
    pattern = re.compile(r"^\s*(?:export\s+)?HYBRID_TOOLCHAIN\s*=\s*(.+?)\s*$")
    for line in cfg.read_text().splitlines():
        m = pattern.match(line)
        if m:
            return m.group(1).strip().strip('"').strip("'")
    return None


def _doctor_artifacts() -> list[_DoctorRow]:
    rows: list[_DoctorRow] = []
    for label, path in _resolve_artifacts().items():
        if path.is_file():
            rows.append((label, "PASS", str(path)))
        else:
            rows.append((label, "FAIL",
                         f"missing {path} -- run ./hsim build"))
    simpoint = REPO_ROOT / "tools" / "simpoint" / "bin" / "simpoint"
    if simpoint.is_file():
        rows.append(("simpoint", "PASS", str(simpoint)))
    else:
        rows.append(("simpoint", "FAIL",
                     f"missing {simpoint} -- run ./hsim build --what simpoint"))
    fix_dir = REPO_ROOT / "tests" / "fixtures"
    elfs = sorted(fix_dir.glob("*.elf")) if fix_dir.is_dir() else []
    if elfs:
        rows.append(("fixtures", "PASS", f"{len(elfs)} ELFs in {fix_dir}"))
    else:
        rows.append(("fixtures", "FAIL",
                     f"no *.elf in {fix_dir} -- run make -C tests/fixtures"))
    return rows


def _doctor_submodules() -> list[_DoctorRow]:
    markers = [
        ("QEMU/",           REPO_ROOT / "QEMU" / "configure"),
        ("verilator/",      REPO_ROOT / "verilator" / "CMakeLists.txt"),
        ("tools/simpoint/", REPO_ROOT / "tools" / "simpoint" / "Makefile"),
    ]
    rows: list[_DoctorRow] = []
    for name, marker in markers:
        if marker.is_file():
            rows.append((name, "PASS", str(marker.relative_to(REPO_ROOT))))
        else:
            rows.append((name, "FAIL",
                         f"missing {marker} -- "
                         f"run 'git submodule update --init --recursive'"))
    return rows


def _doctor_toolchain() -> list[_DoctorRow]:
    rows: list[_DoctorRow] = []
    for tool in ("ninja", "make", "podman"):
        found = shutil.which(tool)
        if found:
            rows.append((tool, "PASS", found))
        else:
            severity = "WARN" if tool == "podman" else "FAIL"
            hint = {
                "ninja":  "needed by ./hsim build of QEMU",
                "make":   "needed by ./hsim build of fixtures + simpoint",
                "podman": "needed by ./hsim build of vsim (or docker shim)",
            }[tool]
            rows.append((tool, severity, f"not on PATH -- {hint}"))
    tc = _read_hybrid_toolchain()
    if not tc:
        rows.append(("HYBRID_TOOLCHAIN", "WARN",
                     "not set -- needed for fixture build "
                     "(see config.env)"))
    else:
        gcc = Path(tc) / "bin" / "riscv64-unknown-elf-gcc"
        if gcc.is_file():
            rows.append(("riscv64-unknown-elf-gcc", "PASS", str(gcc)))
        else:
            rows.append(("riscv64-unknown-elf-gcc", "FAIL",
                         f"missing {gcc} -- check HYBRID_TOOLCHAIN={tc}"))
    return rows


def _doctor_runtime() -> list[_DoctorRow]:
    rows: list[_DoctorRow] = []
    nproc = os.cpu_count() or 1
    rows.append(("nproc", "INFO", str(nproc)))
    shm = Path("/dev/shm")
    if shm.is_dir():
        free_gb = shutil.disk_usage(shm).free // (1024 ** 3)
        status = "PASS" if free_gb >= 4 else "WARN"
        rows.append(("/dev/shm free", status, f"{free_gb} GB"))
    else:
        rows.append(("/dev/shm", "WARN",
                     "not present -- e2e fixtures will fall back to $TMPDIR"))
    suggested = min(nproc, _DEFAULT_JOBS)
    rows.append(("JOBS suggestion", "INFO",
                 f"{suggested} (default cap = {_DEFAULT_JOBS})"))
    return rows


def cmd_doctor(args: argparse.Namespace) -> int:
    sections: list[tuple[str, list[_DoctorRow]]] = [
        ("artifacts",  _doctor_artifacts()),
        ("submodules", _doctor_submodules()),
        ("toolchain",  _doctor_toolchain()),
        ("runtime",    _doctor_runtime()),
    ]
    name_width = max(len(name)
                     for _, rows in sections
                     for name, _, _ in rows)
    totals = {"PASS": 0, "FAIL": 0, "WARN": 0, "INFO": 0}
    for title, rows in sections:
        print(f"{title}:")
        for name, status, detail in rows:
            totals[status] = totals.get(status, 0) + 1
            print(f"  [{status:<4}] {name.ljust(name_width)}  {detail}")
        print()
    print(f"Summary: {totals['PASS']} PASS, {totals['FAIL']} FAIL, "
          f"{totals['WARN']} WARN")
    return 1 if totals["FAIL"] > 0 else 0


# --- main -------------------------------------------------------------------

